key = "asc_downpour",
    hide_ability = false,
    atlas = 'blindside_tags',
    config = {
        extra = {
            odds = 4,
            odds_gain = 4
        }
    },
    blindside = true,
    loc_vars = function (self, info_queue, tag)
        info_queue[#info_queue + 1] = {key = 'bld_modifiers', set = 'Other'}
        local n,d = SMODS.get_probability_vars(tag, 1, 4)
        return {
            vars = {
                n,
                d,
            }
        }
    end,
    pos = {x = 5, y = 3},
    in_pool = function(self, args)
        return false
    end,
    apply = function(self, tag, context)
        if context.type == 'shop_start' and not (next(SMODS.find_card("j_bld_taglock")) and not (G.GAME.blind.boss or G.GAME.last_joker)) then
            tag:yep('+', G.C.RED, function() 
                return true end)
            tag.triggered = true
        end
        if context.type == 'after_hand' then
            for key, value in pairs(G.play.cards) do
                if (value.edition or value.seal) and SMODS.pseudorandom_probability(tag, pseudoseed('bld_downpour'), 1, 4, 'bld_downpour') then
                    G.E_MANAGER:add_event(Event({
                        trigger = 'before',
                        delay = 0.4,
                        func = function()
                            value:set_edition(nil)
                            value:set_seal(nil)
                            play_sound('cardFan2')
                            value:juice_up()
                            return true
                        end
                    }))
                end
            end
        end
    end,

key = "extrajoker",
        dependencies = {
            items = {
                "set_entr_inversions",
            }
        },
        set = "mtx",
        inversion = "c_hpot_justice",
        atlas = "crossmod_consumables",
        pos = {
            x = 5,
            y = 5
        },
        entr_credits = {
            art = { "LFMoth" },
            idea = { "LFMoth" },
            code = { "LFMoth" },
        },
        config = {
            extra = {
                slots = 1,
                credits = 700
            },
        },
        loc_vars = function(self, info_queue, card)
            return {
                vars = { card.ability.extra.slots, card.ability.extra.credits },
            }
        end,
        can_use = function(self, card)
            if G.GAME.seeded == true and G.GAME.budget >= card.ability.extra.credits then         -- check if run is seeded, check seeded creds
                return true
            elseif G.PROFILES[G.SETTINGS.profile].TNameCredits >= card.ability.extra.credits then -- otherwise, check normal creds
                return true
            else
                return false
            end
        end,
        use = function(self, card, area, copier)
            G.E_MANAGER:add_event(Event({
                func = function()
                    HPTN.ease_credits(-card.ability.extra.credits, false) -- remove credits
                    return true
                end,
            }))
            G.E_MANAGER:add_event(Event({
                func = function()
                    if G.jokers then
                        G.jokers.config.card_limit = G.jokers.config.card_limit + card.ability.extra.slots
                    end
                    return true
                end,
            }))
        end,
        demicoloncompat = true,
        force_use = function(self, card) self:use(card) end

